const e=JSON.parse('{"key":"v-2b3d85c0","path":"/%E8%AF%81%E5%88%B8%E4%BA%A4%E6%98%93/%E6%97%A5%E6%9C%AC%E8%9C%A1%E7%83%9B%E5%9B%BE%E6%8A%80%E6%9C%AF/01-%E5%8F%8D%E8%BD%AC%E5%BD%A2%E6%80%81.html","title":"反转形态","lang":"zh-CN","frontmatter":{"date":"2024-01-17T00:00:00.000Z","category":["证券交易"],"tag":["反转形态"],"order":1,"description":"反转形态 绘制蜡烛图的方法 image-20240117145421606 在绘制日线图的时候，每根图线需要开市价、最高价、最低价和收市价四种价格。线图的图线主要由若干竖直的线段组成，它们表示了各个对应时间段的最高价和最低价之间的范围。从每根竖直线段上，向左伸出一小段横线头，表示对应时间段内的开市价(最初价)。从每根图线上向右伸出一小段横线头，代表对应时间段内的收市价(最后价)。 在蜡烛图的图线内部，有一段胖鼓鼓的部分，称为实体。它表示了相应交易日的开市价与收市价之间的价格范围。如果实体是黑色的(即，将之涂满黑色)，则代表当日的收市价低于开市价。如果实体是白色的(即，将它保留为空白)，则表示当日收市价高于开市价。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/%E8%AF%81%E5%88%B8%E4%BA%A4%E6%98%93/%E6%97%A5%E6%9C%AC%E8%9C%A1%E7%83%9B%E5%9B%BE%E6%8A%80%E6%9C%AF/01-%E5%8F%8D%E8%BD%AC%E5%BD%A2%E6%80%81.html"}],["meta",{"property":"og:site_name","content":"Journey of Growth"}],["meta",{"property":"og:title","content":"反转形态"}],["meta",{"property":"og:description","content":"反转形态 绘制蜡烛图的方法 image-20240117145421606 在绘制日线图的时候，每根图线需要开市价、最高价、最低价和收市价四种价格。线图的图线主要由若干竖直的线段组成，它们表示了各个对应时间段的最高价和最低价之间的范围。从每根竖直线段上，向左伸出一小段横线头，表示对应时间段内的开市价(最初价)。从每根图线上向右伸出一小段横线头，代表对应时间段内的收市价(最后价)。 在蜡烛图的图线内部，有一段胖鼓鼓的部分，称为实体。它表示了相应交易日的开市价与收市价之间的价格范围。如果实体是黑色的(即，将之涂满黑色)，则代表当日的收市价低于开市价。如果实体是白色的(即，将它保留为空白)，则表示当日收市价高于开市价。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2024-01-23T16:52:01.000Z"}],["meta",{"property":"article:author","content":"Mr.G"}],["meta",{"property":"article:tag","content":"反转形态"}],["meta",{"property":"article:published_time","content":"2024-01-17T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2024-01-23T16:52:01.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"反转形态\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2024-01-17T00:00:00.000Z\\",\\"dateModified\\":\\"2024-01-23T16:52:01.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Mr.G\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"绘制蜡烛图的方法","slug":"绘制蜡烛图的方法","link":"#绘制蜡烛图的方法","children":[]},{"level":2,"title":"反转形态","slug":"反转形态-1","link":"#反转形态-1","children":[]},{"level":2,"title":"锤子线和上吊线","slug":"锤子线和上吊线","link":"#锤子线和上吊线","children":[]},{"level":2,"title":"吞没形态(抱线形态）","slug":"吞没形态-抱线形态","link":"#吞没形态-抱线形态","children":[]},{"level":2,"title":"乌云盖顶形态(乌云线形态)","slug":"乌云盖顶形态-乌云线形态","link":"#乌云盖顶形态-乌云线形态","children":[]},{"level":2,"title":"刺透形态(斩回线形态)","slug":"刺透形态-斩回线形态","link":"#刺透形态-斩回线形态","children":[]}],"git":{"createdTime":1705570195000,"updatedTime":1706028721000,"contributors":[{"name":"gm-hacker","email":"gm-hacker@qq.com","commits":2}]},"readingTime":{"minutes":39.76,"words":11928},"filePathRelative":"证券交易/日本蜡烛图技术/01-反转形态.md","localizedDate":"2024年1月17日","excerpt":"<h1> 反转形态</h1>\\n<h2> 绘制蜡烛图的方法</h2>\\n<figure><figcaption>image-20240117145421606</figcaption></figure>\\n<p>在绘制日线图的时候，每根图线需要开市价、最高价、最低价和收市价四种价格。线图的图线主要由若干竖直的线段组成，它们表示了各个对应时间段的最高价和最低价之间的范围。从每根竖直线段上，向左伸出一小段横线头，表示对应时间段内的开市价(最初价)。从每根图线上向右伸出一小段横线头，代表对应时间段内的收市价(最后价)。</p>\\n<p>在蜡烛图的图线内部，有一段胖鼓鼓的部分，称为实体。它表示了相应交易日的开市价与收市价之间的价格范围。如果实体是黑色的(即，将之涂满黑色)，则代表当日的收市价低于开市价。如果实体是白色的(即，将它保留为空白)，则表示当日收市价高于开市价。</p>","autoDesc":true}');export{e as data};
